import{c as e,Q as a,j as i,m as t}from"./chunks/framework.iD28w_5a.js";const k=JSON.parse('{"title":"028c-fs-cwd-stat-1 · CWD 与 Stat","description":"","frontmatter":{"title":"028c-fs-cwd-stat-1 · CWD 与 Stat"},"headers":[],"relativePath":"hands-on/028c-fs-cwd-stat-1.md","filePath":"hands-on/028c-fs-cwd-stat-1.md","lastUpdated":1779686691000}'),o={name:"hands-on/028c-fs-cwd-stat-1.md"};function d(c,s,n,l,p,h){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="_028c-1-hands-on-路径解析与进程工作目录" tabindex="-1">028c-1 Hands-on: 路径解析与进程工作目录 <a class="header-anchor" href="#_028c-1-hands-on-路径解析与进程工作目录" aria-label="Permalink to &quot;028c-1 Hands-on: 路径解析与进程工作目录&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一个 tag 我们把 ext2 的写路径打通了——touch 能创建文件、mkdir 能建目录、rm 能删除、echo 能写数据。但如果你在 Shell 里试过 <code>cd /etc</code> 然后跑 <code>cat passwd</code>，你会发现两件事：第一，cd 根本不存在；第二，就算你用绝对路径 <code>cat /etc/passwd</code> 能工作，但一旦你想用相对路径就彻底完蛋——因为内核根本不知道&quot;当前目录&quot;是什么概念。</p><p>这个问题的本质在于，我们之前的文件系统操作只认绝对路径。每个 syscall 拿到的路径字符串必须以 <code>/</code> 开头，否则 VFS 就不知道你在说什么。但真实的用户空间程序几乎不可能一直用绝对路径——想一想你平时在终端里敲 <code>vim main.cpp</code> 的时候，你不会写 <code>vim /home/charliechen/project/src/main.cpp</code> 吧？操作系统需要维护一个&quot;进程当前工作目录&quot;（current working directory，CWD），然后在打开文件时把相对路径拼接到 CWD 上，转换成绝对路径再交给 VFS 处理。</p><p>这一章我们要做三件事：在进程控制结构里加上 CWD 字段，实现一套路径规范化算法（处理 <code>.</code>、<code>..</code>、多余的 <code>/</code>），然后把这两者组合起来做成一个统一的路径解析工具。完成之后，所有的文件系统 syscall 就都能处理相对路径了。</p><p>知识前置：028a（ext2 只读驱动和 VFS 挂载）、028b（ext2 写操作和 Shell 基本命令）。需要理解 Task 结构体、Scheduler 的 current 指针、VFS 挂载表的 resolve 流程。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="进程工作目录-——-你现在在哪" tabindex="-1">进程工作目录 —— &quot;你现在在哪？&quot; <a class="header-anchor" href="#进程工作目录-——-你现在在哪" aria-label="Permalink to &quot;进程工作目录 —— &quot;你现在在哪？&quot;&quot;">​</a></h3><p>每个 Unix 进程都有一个 CWD，它是一个绝对路径字符串，表示进程当前所处的目录位置。当你执行 <code>open(&quot;foo.txt&quot;)</code> 的时候，内核实际打开的是 <code>{cwd}/foo.txt</code>。CWD 不是什么硬件概念，纯粹是内核为每个进程维护的一块软件状态。</p><p>在 Linux 里，CWD 存储在 <code>task_struct-&gt;fs-&gt;pwd</code> 中，类型是 <code>struct path</code>（包含一个指向 dentry 和 vfsmount 的指针）。Cinux 的做法更简单直接——我们在 <code>Task</code> 结构体里直接塞一个 <code>char cwd[256]</code> 字段，存的是绝对路径字符串。256 字节对教学内核来说绰绰有余了——Linux 的 PATH_MAX 也是 4096，但我们的路径不会那么长。</p><p>进程创建的时候，CWD 初始化为根目录 <code>&quot;/&quot;</code>。Cinux 目前还没有 fork/execve，Shell 进程是在 <code>kernel/arch/x86_64/usermode.cpp</code> 的 <code>launch_first_user()</code> 中通过创建一个 <code>static Task shell_task{}</code> 并设置 <code>.cwd[0] = &#39;/&#39;</code> 来启动的，所以初始化阶段只要把第一个进程的 CWD 设为 <code>/</code> 就行。</p><h3 id="路径规范化-——-把乱七八糟的路径收拾干净" tabindex="-1">路径规范化 —— 把乱七八糟的路径收拾干净 <a class="header-anchor" href="#路径规范化-——-把乱七八糟的路径收拾干净" aria-label="Permalink to &quot;路径规范化 —— 把乱七八糟的路径收拾干净&quot;">​</a></h3><p>用户传入的路径可能千奇百怪：<code>/a/b/../c</code>、<code>/a/./b/./c</code>、<code>/a//b///c</code>、<code>/a/b/</code>、<code>/../../x</code>。路径规范化（canonicalization）的目标是把所有这些路径都转换成唯一的标准形式——一个从根目录开始的、不包含 <code>.</code> 或 <code>..</code> 的、不以 <code>/</code> 结尾（根目录除外）的绝对路径。</p><p>规范化的核心算法是这样的：从左到右扫描路径中的每个&quot;组件&quot;（被 <code>/</code> 分隔的字符串），遇到普通组件就压入栈，遇到 <code>.</code> 就跳过，遇到 <code>..</code> 就弹出栈顶。最后把栈里的组件用 <code>/</code> 连起来就是规范路径。这个算法有一个重要的边界条件：<code>..</code> 不能弹出根目录——<code>/../../a</code> 的规范结果是 <code>/a</code>，不是什么&quot;根目录的上一级&quot;。因为在文件系统的语义里，根目录就是最顶层，不存在&quot;往上&quot;的概念。</p><h3 id="路径解析-——-把-cwd-和用户路径合体" tabindex="-1">路径解析 —— 把 CWD 和用户路径合体 <a class="header-anchor" href="#路径解析-——-把-cwd-和用户路径合体" aria-label="Permalink to &quot;路径解析 —— 把 CWD 和用户路径合体&quot;">​</a></h3><p>有了规范化和 CWD 之后，路径解析的逻辑就非常直白了。如果用户传入的路径以 <code>/</code> 开头（绝对路径），直接拿去做规范化就行。如果不是以 <code>/</code> 开头（相对路径），就把 <code>cwd + &quot;/&quot; + path</code> 拼起来再做规范化。比如 cwd 是 <code>/home/user</code>，用户传了 <code>../bin</code>，拼接后是 <code>/home/user/../bin</code>，规范化后是 <code>/home/bin</code>。</p><p>这里有一个细节值得注意：拼接之前要检查 cwd 本身是不是以 <code>/</code> 结尾。如果 cwd 是 <code>/</code>（根目录），那直接拼 <code>/</code> + <code>foo</code> 就是 <code>//foo</code>，规范化后是 <code>/foo</code>——这没问题。但如果 cwd 是 <code>/home/user</code>（不以 <code>/</code> 结尾），就要加一个 <code>/</code> 分隔符，否则拼出来是 <code>/home/userfoo</code>，那就完全不对了。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-在-task-结构体中添加-cwd-字段" tabindex="-1">Step 1: 在 Task 结构体中添加 CWD 字段 <a class="header-anchor" href="#step-1-在-task-结构体中添加-cwd-字段" aria-label="Permalink to &quot;Step 1: 在 Task 结构体中添加 CWD 字段&quot;">​</a></h3><p><strong>目标</strong>: 为进程控制块增加当前工作目录的存储空间。</p><p><strong>设计思路</strong>: 在 <code>Task</code> 结构体末尾添加 <code>char cwd[256]</code> 字段。选择 256 字节而不是更小的值，是因为要容纳一定深度的目录路径。选择固定大小数组而不是动态分配，是为了避免在内核里引入堆分配的复杂性。字段初始化为 <code>&quot;/&quot;</code>。</p><p><strong>实现约束</strong>: 新字段添加在 <code>fpu_state[512]</code> 之后。所有创建 Task 的代码路径（包括 <code>TaskBuilder::build()</code> 和通过 <code>fork()</code> 复制 Task 的路径）都需要确保 cwd 被正确初始化。</p><p><strong>验证</strong>: 编译通过，确认 sizeof(Task) 变化合理：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_common</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="step-2-实现-path-canonicalize" tabindex="-1">Step 2: 实现 path_canonicalize <a class="header-anchor" href="#step-2-实现-path-canonicalize" aria-label="Permalink to &quot;Step 2: 实现 path_canonicalize&quot;">​</a></h3><p><strong>目标</strong>: 编写路径规范化函数，能正确处理 <code>.</code>、<code>..</code>、连续 <code>/</code>、尾随 <code>/</code> 等情况。</p><p><strong>设计思路</strong>: 使用一个临时缓冲区作为&quot;输出栈&quot;。从左到右扫描输入路径的每个组件，根据组件内容决定操作：<code>.</code> 跳过，<code>..</code> 回退输出指针到上一个 <code>/</code>，普通组件追加到输出缓冲区。最终保证输出一定以 <code>/</code> 开头、不以 <code>/</code> 结尾（根目录除外）。</p><p><strong>实现约束</strong>: 函数签名为 <code>void path_canonicalize(char* buf)</code>，原地修改输入缓冲区。内部使用一个大小为 PATH_MAX（4096）的临时缓冲区，最后 memcpy 回去。需要处理空字符串和 nullptr 的边界情况。</p><p><strong>验证</strong>: 在内核测试里添加单元测试，覆盖以下用例：</p><ul><li><code>/a/b/../c</code> 变成 <code>/a/c</code></li><li><code>/a/./b/./c</code> 变成 <code>/a/b/c</code></li><li><code>/a//b///c</code> 变成 <code>/a/b/c</code></li><li><code>/a/b/</code> 变成 <code>/a/b</code></li><li><code>/</code> 保持 <code>/</code></li><li><code>/././.</code> 变成 <code>/</code></li><li><code>/../../a</code> 变成 <code>/a</code>（<code>..</code> 不能越过根）</li></ul><p>编译并运行测试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./big_kernel_test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;path_canonicalize&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="step-3-实现-path-resolve" tabindex="-1">Step 3: 实现 path_resolve <a class="header-anchor" href="#step-3-实现-path-resolve" aria-label="Permalink to &quot;Step 3: 实现 path_resolve&quot;">​</a></h3><p><strong>目标</strong>: 实现 cwd 感知的路径解析，将用户传入的（可能为相对）路径转换为规范绝对路径。</p><p><strong>设计思路</strong>: 判断路径首字符是否为 <code>/</code>。如果是，直接复制到输出缓冲区后调用 path_canonicalize。如果不是，拼接 <code>cwd + &quot;/&quot; + path</code> 后调用 path_canonicalize。拼接时注意 cwd 末尾是否已有 <code>/</code>。</p><p><strong>实现约束</strong>: 函数签名为 <code>bool path_resolve(const char* cwd, const char* path, char* out)</code>，返回 bool 表示成功/失败。输出缓冲区大小至少 PATH_MAX。需要处理三个参数中任何一个为 nullptr 的情况。</p><p><strong>验证</strong>: 添加测试用例：</p><ul><li>绝对路径透传：<code>path_resolve(&quot;/&quot;, &quot;/usr/bin&quot;, out)</code> 得到 <code>/usr/bin</code></li><li>相对路径拼接：<code>path_resolve(&quot;/home/user&quot;, &quot;docs&quot;, out)</code> 得到 <code>/home/user/docs</code></li><li><code>..</code> 上升：<code>path_resolve(&quot;/home/user&quot;, &quot;..&quot;, out)</code> 得到 <code>/home</code></li><li>nullptr 参数返回 false</li></ul><p>编译并运行测试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./big_kernel_test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;path_resolve&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="step-4-实现-resolve-user-path-和-validate-user-ptr" tabindex="-1">Step 4: 实现 resolve_user_path 和 validate_user_ptr <a class="header-anchor" href="#step-4-实现-resolve-user-path-和-validate-user-ptr" aria-label="Permalink to &quot;Step 4: 实现 resolve_user_path 和 validate_user_ptr&quot;">​</a></h3><p><strong>目标</strong>: 为 syscall 层提供统一的路径解析入口，消除各个 syscall 中的重复代码。</p><p><strong>设计思路</strong>: <code>validate_user_ptr</code> 做一次 x86_64 规范地址检查（bit 47 扩展到 bit 48-63），防止用户传入内核空间的指针。<code>resolve_user_path</code> 在验证指针后，从 <code>Scheduler::current()</code> 获取当前进程的 CWD，然后调用 <code>fs::path_resolve</code> 完成路径解析。</p><p><strong>实现约束</strong>: <code>validate_user_ptr</code> 是 inline 函数，放在头文件中。<code>resolve_user_path</code> 的签名为 <code>bool resolve_user_path(uint64_t path_virt, char* out)</code>。如果 <code>Scheduler::current()</code> 返回 nullptr（理论上不应该发生），则 CWD 回退到 <code>&quot;/&quot;</code>。</p><p><strong>验证</strong>: 这个函数被后续所有路径相关 syscall 使用，暂不单独测试。编译通过即可：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_common</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="step-5-scheduler-set-current-和-cwd-初始化" tabindex="-1">Step 5: Scheduler::set_current 和 CWD 初始化 <a class="header-anchor" href="#step-5-scheduler-set-current-和-cwd-初始化" aria-label="Permalink to &quot;Step 5: Scheduler::set_current 和 CWD 初始化&quot;">​</a></h3><p><strong>目标</strong>: 提供 <code>set_current()</code> 方法用于测试中设置当前进程，确保 CWD 在内核启动流程中被正确初始化。</p><p><strong>设计思路</strong>: <code>Scheduler::set_current(Task* task)</code> 同时更新 <code>current_</code> 静态成员和 <code>g_per_cpu.current</code>。Shell 进程在 <code>launch_first_user()</code> 中通过创建 <code>static Task shell_task{}</code> 并设置 <code>.cwd[0] = &#39;/&#39;</code>、<code>.state = Running</code>，然后调用 <code>set_current(&amp;shell_task)</code> 来注册。测试代码中同样通过 <code>set_current()</code> 注册一个 mock Task 来测试 CWD 相关功能。</p><p><strong>验证</strong>: 运行完整内核测试，确认 CWD 初始值测试通过：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./big_kernel_test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;CWD initial&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>到这里，我们已经搭好了路径解析的全部基础设施：Task 里有 CWD 字段，有能处理各种奇葩路径的规范化算法，有 cwd 感知的路径解析器，还有 syscall 层的统一入口。但光有这些还不够——我们还需要能修改 CWD 的 syscall（chdir）、能读取 CWD 的 syscall（getcwd），以及能查询文件元数据的 syscall（stat）。这些就是下一章的内容了。</p>`,53)])])}const u=e(o,[["render",d]]);export{k as __pageData,u as default};
